import{_ as e,o,c as t,ag as a}from"./chunks/framework-C5-Jzrz4.js";const n=JSON.parse('{"title":"变更日志","description":"项目版本更新记录与变更说明","frontmatter":{"title":"变更日志","description":"项目版本更新记录与变更说明","lastUpdated":true},"headers":[],"relativePath":"scripts/changelog/CHANGELOG.md","filePath":"scripts/changelog/CHANGELOG.md","lastUpdated":null}');const i=e({name:"scripts/changelog/CHANGELOG.md"},[["render",function(e,n,i,l,c,d){return o(),t("div",null,[...n[0]||(n[0]=[a('<h1 id="变更日志" tabindex="-1">变更日志 <a class="header-anchor" href="#变更日志" aria-label="Permalink to &quot;变更日志&quot;">​</a></h1><h2 id="_2-0-0" tabindex="-1">2.0.0 <a class="header-anchor" href="#_2-0-0" aria-label="Permalink to &quot;2.0.0&quot;">​</a></h2><h2 id="环境" tabindex="-1">环境 <a class="header-anchor" href="#环境" aria-label="Permalink to &quot;环境&quot;">​</a></h2><p>最低需要使用<code>node版本&gt;22.16.0</code> 否则会影响编辑器的格式化(需要安装oxc插件)</p><h2 id="变化-跟ant-design-vue对比" tabindex="-1">变化(跟ant-design-vue对比) <a class="header-anchor" href="#变化-跟ant-design-vue对比" aria-label="Permalink to &quot;变化(跟ant-design-vue对比)&quot;">​</a></h2><p>从ant design (react) v6移植过来 详细也可以看<a href="https://ant.design/changelog-cn#600" target="_blank" rel="noreferrer">antd的文档</a></p><ul><li>支持css变量 不用再写<strong>deep</strong>或者加权重来覆盖样式</li><li>支持<code>组件语义化结构</code> <a href="https://ant.design/docs/blog/semantic-beauty-cn" target="_blank" rel="noreferrer">组件语义化结构</a></li><li>notification的新样式 (这个从antd5都已经有了 vue一直没有)</li><li>RadioGroup支持波纹效果</li><li>modal/drawer支持blur效果</li><li>支持颜色与变体 需要绿色按钮？不用再写css了<a href="https://ant.design/components/button-cn#button-demo-color-variant" target="_blank" rel="noreferrer">Button 组件</a></li><li>支持颜色选择器<a href="https://ant.design/components/color-picker-cn" target="_blank" rel="noreferrer">ColorPicker 组件</a> 这个也是从antd5就开始有了 vue一直没有</li><li>一些xxxItem组件 如<code>DescriotionsItem</code> <code>MenuItem</code> <code>TimeLineItem</code> 已经移除 使用对应父组件的<code>items</code>属性代替</li><li>DatePicker等必须绑定为<code>Dayjs</code>类型 不再支持<code>string</code>格式的绑定 相应需要提交自己转为string提交</li></ul><h2 id="框架级别的变化" tabindex="-1">框架级别的变化 <a class="header-anchor" href="#框架级别的变化" aria-label="Permalink to &quot;框架级别的变化&quot;">​</a></h2><ul><li>v1版本的<code>requestClient</code>已经被<code>alovaInstance</code>替代 已经做了兼容(99%) 可直接替换</li><li>表格的操作列<code>ghost-button</code>替换名称为<code>action-button</code> 现在你可以修改来默认样式</li><li>message/modal/notification直接导入使用(静态方法)无法获取context 即主题/国际化无效 需要通过<code>window.xxx</code>进行调用</li><li>使用<code>version-polling</code>替代自带的版本检测更新 样式更新 在worker执行 不会阻塞主线程</li><li>字典常量enum从<code>packages/@core/base/shared/src/constants</code>移动到<code>@vben/constants</code>下 需要移动文件位置(导入不需要更改)</li><li><s>Switch的value只能是boolean值 之前可以为 string/number/boolean (antd组件变化)</s> 后续rc版本又加上了</li><li>Popconfirm不再需要 <code>:get-popup-container=&quot;getVxePopupContainer&quot;</code> antd已经支持滚动跟随 故<code>getVxePopupContainer</code>已经移除</li><li>离线(菜单)图标方案重构 在<code>scripts/generate-offline-icons.js</code>添加图标名称 在根目录执行<code>pnpm generate-offline-icons</code>即可生成离线图标</li><li><s>表格上方搜索表单(或者需要调用formReset的场景) -&gt; 时间相关组件必须设置<code>defaultValue</code>为<code>null</code>(区间时间组件需要设置为[null, null]的元组) <strong>否则不会正常重置</strong></s> 后续版本已经修复</li><li>移除<code>commonDownloadExcel</code>方法 使用<code>useBlobExport</code>代替</li><li>路由模式由<code>backend</code>改为<code>mix</code>模式 即前后端混合路由 路由放在<code>apps/web-antd/src/router/routes/modules</code>下 移除原先的<code>local.ts</code></li></ul><h2 id="vben基础框架的变化" tabindex="-1">vben基础框架的变化 <a class="header-anchor" href="#vben基础框架的变化" aria-label="Permalink to &quot;vben基础框架的变化&quot;">​</a></h2><ul><li>使用<code>oxc</code>替代<code>eslint</code> &amp; <code>prettier</code></li><li>tailwind3 -&gt; tailwind4</li><li>vite升级到v8(基于rust)</li><li>core包<code>unbuild</code>升级到<code>tsdown</code>(基于rust)</li></ul>',11)])])}]]);export{n as __pageData,i as default};
